import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';
import { UserRepository } from './user.repository';

export interface IAuthService {
  login(username: string, password: string): Promise<string>;
}

export class AuthService implements IAuthService {
  constructor(
    private userRepository: UserRepository,
    private jwtSecret: string
  ) {}

  async login(username: string, password: string): Promise<string> {
    const user = await this.userRepository.findByUsername(username);
    if (!user) {
      throw new Error('Invalid credentials');
    }
    const valid = await bcrypt.compare(password, user.passwordHash);
    if (!valid) {
      throw new Error('Invalid credentials');
    }
    const payload = { sub: user.employeeId, role: user.role };
    return jwt.sign(payload, this.jwtSecret, { expiresIn: '8h' });
  }
}","File: src/modules/auth/auth.middleware.ts
import { FastifyRequest, FastifyReply } from 'fastify';
import jwt from 'jsonwebtoken';

export async function authenticateJWT(
  request: FastifyRequest,
  reply: FastifyReply
): Promise<void> {
  const authHeader = request.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    reply.status(401).send({ error: 'Missing or invalid token' });
    return;
  }
  const token = authHeader.substring(7);
  try {
    const decoded = jwt.verify(token, request.server.config.JWT_SECRET) as { sub: string; role: string };
    request.user = { employeeId: decoded.sub, role: decoded.role };
  } catch (err) {
    reply.status(401).send({ error: 'Invalid token' });
  }
}

export function requireRole(role: string) {
  return async (request: FastifyRequest, reply: FastifyReply): Promise<void> => {
    if (!request.user || request.user.role !== role) {
      reply.status(403).send({ error: 'Forbidden' });
    }
  };
}","File: src/modules/auth/auth.controller.ts
import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { AuthService } from './auth.service';
import { UserRepository } from './user.repository';
import { loginSchema, LoginRequest } from './auth.dto';
import { authenticateJWT } from './auth.middleware';
import { Pool } from '../../shared/db/connection';

export default async function authRoutes(
  fastify: FastifyInstance,
  opts: { pool: Pool; jwtSecret: string }
): Promise<void> {
  const userRepo = new UserRepository(opts.pool);
  const authService = new AuthService(userRepo, opts.jwtSecret);

  fastify.post<{ Body: LoginRequest }>(
    '/auth/login',
    { schema: { body: loginSchema } },
    async (request, reply) => {
      try {
        const token = await authService.login(request.body.username, request.body.password);
        return { token };
      } catch (err) {
        if (err.message === 'Invalid credentials') {
          reply.status(401).send({ error: 'Invalid credentials' });
        } else {
          request.log.error(err);
          reply.status(500).send({ error: 'Internal server error' });
        }
      }
    }
  );

  fastify.post(
    '/auth/logout',
    { preHandler: authenticateJWT },
    async (request, reply) => {
      return { message: 'Logged out successfully' };
    }
  );

  fastify.decorateRequest('user', null);
  fastify.addHook('onRequest', async (request) => {
    // user population is handled by authenticateJWT middleware on protected routes
  });
}","File: src/modules/auth/index.ts
